// MITRE: T1082 (System Information Discovery), T1074 (Data Staged)
// Hunt: id.txt creation in APPDATA — victim fingerprinting artifact
// DeviceFileEvents: NO AccountName column — use InitiatingProcessAccountName
DeviceFileEvents
| where ActionType in ("FileCreated", "FileModified")
| where FolderPath has @"\AppData\Roaming"
| where FileName =~ "id.txt"
| project-reorder TimeGenerated, DeviceName, InitiatingProcessAccountName, InitiatingProcessFileName, InitiatingProcessFolderPath, FolderPath, FileName, SHA256
| sort by TimeGenerated desc
